class Solution {
    public String robotWithString(String s) {
        StringBuilder t = new StringBuilder();
        while (s.length() != 0) {
            t.deleteCharAt(0);
            s = s.substring(1);
            t.append(s.charAt(0));
        }
        return t.toString();
    }
}
